namespace sv_d0444ea63647485699225edd8fc869fe.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_d0444ea63647485699225edd8fc869fe.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 50
            ? Channel.Description[..50] + "…"
            : Channel.Description;
}

.channel-item {
    padding: 10px 14px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.12);
    border-left-color: #5865f2;
}

.channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #dcddde;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.78rem;
    color: #8e9297;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    background-color: #40444b;
    border-top: 1px solid #2f3136;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    background-color: #40444b;
    border: 1px solid #202225;
    border-radius: 8px;
    color: #dcddde;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    resize: none;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #5865f2;
}

.message-input textarea::placeholder {
    color: #72767d;
}

.send-button {
    background-color: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.send-button:hover:not(:disabled) {
    background-color: #4752c4;
}

.send-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_d0444ea63647485699225edd8fc869fe.Services

<div class="message-bubble"
     @onmouseenter="() => showActions = true"
     @onmouseleave="HideActions">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge"
                        @onclick="() => OnReact.InvokeAsync(reaction.Emoji)"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions && ShowActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync()" title="Reply in thread">💬 Reply</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😊 React</button>
        </div>

        @if (showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in commonEmojis)
                {
                    <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool ShowActions { get; set; } = true;
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-bubble {
    position: relative;
    padding: 8px 16px;
    transition: background-color 0.1s;
    border-radius: 4px;
}

.message-bubble:hover {
    background-color: rgba(4, 4, 5, 0.07);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    font-size: 0.9rem;
    color: #dcddde;
    line-height: 1.4;
    word-wrap: break-word;
}

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background-color: rgba(88, 101, 242, 0.15);
    border: 1px solid rgba(88, 101, 242, 0.3);
    border-radius: 8px;
    padding: 2px 8px;
    font-size: 0.8rem;
    color: #dcddde;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: rgba(88, 101, 242, 0.3);
}

.thread-link {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 8px;
    display: flex;
    gap: 2px;
    background-color: #2f3136;
    border: 1px solid #202225;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 0.78rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.1s, color 0.1s;
    white-space: nowrap;
}

.action-btn:hover {
    background-color: rgba(255, 255, 255, 0.08);
    color: #dcddde;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 160px;
    display: flex;
    gap: 2px;
    background-color: #2f3136;
    border: 1px solid #202225;
    border-radius: 6px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 11;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.emoji-btn:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

