.message-bubble {
    position: relative;
    padding: 8px 16px;
    transition: background-color 0.1s;
    border-radius: 4px;
}

.message-bubble:hover {
    background-color: rgba(4, 4, 5, 0.07);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    font-size: 0.9rem;
    color: #dcddde;
    line-height: 1.4;
    word-wrap: break-word;
}

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background-color: rgba(88, 101, 242, 0.15);
    border: 1px solid rgba(88, 101, 242, 0.3);
    border-radius: 8px;
    padding: 2px 8px;
    font-size: 0.8rem;
    color: #dcddde;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: rgba(88, 101, 242, 0.3);
}

.thread-link {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 8px;
    display: flex;
    gap: 2px;
    background-color: #2f3136;
    border: 1px solid #202225;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 0.78rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.1s, color 0.1s;
    white-space: nowrap;
}

.action-btn:hover {
    background-color: rgba(255, 255, 255, 0.08);
    color: #dcddde;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 160px;
    display: flex;
    gap: 2px;
    background-color: #2f3136;
    border: 1px solid #202225;
    border-radius: 6px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 11;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.emoji-btn:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

