@using sv_d0444ea63647485699225edd8fc869fe.Services
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-area">
    <div class="area-header">
        <h3># @ChannelName</h3>
        <p>@ChannelDescription</p>
    </div>

    <div class="message-list" @ref="messageListRef">
        @if (HasMoreMessages)
        {
            <div class="load-more-sentinel" @ref="sentinelRef"></div>
            <button class="load-more-btn" @onclick="OnLoadMore">⬆ Load older messages</button>
        }
        @foreach (var message in Messages)
        {
            <MessageBubble Message="message"
                           ReplyCount="GetReplyCount(message.Id)"
                           OnOpenThread="() => OnOpenThread.InvokeAsync(message.Id)"
                           OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
        }
        <div @ref="bottomRef"></div>
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")" OnSend="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;
    private ElementReference sentinelRef;
    private ElementReference bottomRef;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<MessageArea>? dotNetRef;
    private bool shouldScrollToBottom = true;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Chat/MessageArea.razor.js");
            await jsModule.InvokeVoidAsync("initialize", messageListRef, dotNetRef);
        }

        if (shouldScrollToBottom && jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
            shouldScrollToBottom = false;
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnLoadMore.InvokeAsync();
    }

    public void RequestScrollToBottom()
    {
        shouldScrollToBottom = true;
    }

    private int GetReplyCount(int messageId)
        => ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("dispose");
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

.message-area {
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    background-color: #36393f;
    overflow: hidden;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
    flex-shrink: 0;
}

.area-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.area-header p {
    margin: 2px 0 0;
    font-size: 0.8rem;
    color: #8e9297;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.load-more-btn {
    align-self: center;
    background: none;
    border: 1px solid #4f545c;
    border-radius: 6px;
    color: #b9bbbe;
    padding: 6px 16px;
    font-size: 0.8rem;
    cursor: pointer;
    margin: 8px 0;
    transition: background-color 0.15s, color 0.15s;
}

.load-more-btn:hover {
    background-color: rgba(255, 255, 255, 0.06);
    color: #dcddde;
}

.load-more-sentinel {
    height: 1px;
    width: 100%;
}

let observer = null;

export function initialize(messageList, dotNetRef) {
    if (!messageList) return;

    // Detect scroll to top for loading older messages
    messageList.addEventListener('scroll', () => {
        if (messageList.scrollTop === 0) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    });
}

export function scrollToBottom(messageList) {
    if (messageList) {
        messageList.scrollTop = messageList.scrollHeight;
    }
}

export function dispose() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

